// cdp_router — pair scraper HTTP responses to SKUs for sheet PROCESSADO updates.

const httpItems = $input.all();
const batches = $('⚙️ Formatar Payload Scraper').all();
const out = [];
const PROCESSING = '⏳ Processando';

for (let i = 0; i < httpItems.length; i++) {
  const resp = httpItems[i].json;
  const hasJob = Boolean(resp.job_id);
  const sc = resp.statusCode != null ? Number(resp.statusCode) : hasJob ? 200 : 0;
  if (!hasJob && (sc < 200 || sc >= 300)) continue;
  const batch = batches[i]?.json;
  if (!batch) continue;
  const rows = Array.isArray(batch.sheet_rows) ? batch.sheet_rows : batch.items || [];
  for (const it of rows) {
    if (!it || !it.sku) continue;
    const rowNumber = it.row_number;
    if (rowNumber === undefined || rowNumber === null || rowNumber === '') continue;
    out.push({
      json: {
        sku: String(it.sku).trim(),
        row_number: rowNumber,
        PROCESSADO: PROCESSING,
        ENCONTRADO: PROCESSING,
        NOTIFICADO: PROCESSING,
      },
    });
  }
}
return out;

const item = $input.first().json;
const batchIndex = item.batch_index || 'unknown';
const totalBatches = item.total_batches || 'unknown';
const errorMsg = item.error || item.message || item.detail || JSON.stringify(item).substring(0, 500);
const statusCode = item.status_code ?? item.statusCode ?? 'N/A';
function env(name) { try { if (typeof process !== 'undefined' && process.env && process.env[name]) return String(process.env[name]).trim(); } catch (e) {} return ''; }
const emailTo = String(item.reply_email || item.email_from || env('NOTIFICATION_EMAIL_TO') || '').trim();
const nowIso = new Date().toISOString();

const historico = {
  job_id: String(item.job_id || `dispatch-batch-${batchIndex}`),
  origem: String(item.origem || 'dispatcher_error'),
  solicitante: String(item.reply_email || item.email_from || item.chat_id || ''),
  disparado_em: String(item.dispatched_at || nowIso),
  concluido_em: nowIso,
  tempo_segundos: '0',
  status: '❌ ERRO_DISPATCH',
  skus_lidos: String(item.batch_size || 0),
  skus_validos: String(item.batch_size || 0),
  skus_encontrados: '0',
  skus_falhos: String(item.batch_size || 0),
  taxa_sucesso_sku: '0%',
  taxa_sucesso_sites: '0%',
  sites_pesquisados: '0',
  resumo_sites: '{}',
  lista_skus_csv: String((item.items || []).map(i => i.sku).filter(Boolean).join(', ')),
  job_error: `[HTTP ${statusCode}] ${String(errorMsg).substring(0, 1000)}`
};

let html = '<h2>❌ CDP Job Dispatcher — API Error</h2>';
html += '<p><strong>Time:</strong> ' + nowIso + '</p>';
html += '<p><strong>Batch:</strong> ' + batchIndex + ' / ' + totalBatches + '</p>';
html += '<p><strong>HTTP Status:</strong> ' + statusCode + '</p>';
html += '<p><strong>Error:</strong></p>';
html += '<pre style="background:#fee2e2;padding:12px;border-radius:8px">' + errorMsg + '</pre>';
html += '<p style="color:#718096;font-size:12px">Automated alert from CDP Job Dispatcher.</p>';

return [{ json: { ...historico, email_from: emailTo, email_subject: '❌ Dispatcher Error — Batch ' + batchIndex, email_html: html } }];

// cdp_router — pass SKUs through; optional random sample via CDP_DISPATCH_SAMPLE_SIZE (0 = all).

function env(name) {
  try {
    if (typeof $env !== 'undefined' && $env && $env[name]) {
      return String($env[name]).trim();
    }
  } catch (e) {}
  try {
    if (typeof process !== 'undefined' && process.env && process.env[name]) {
      return String(process.env[name]).trim();
    }
  } catch (e) {}
  return '';
}
function envInt(name, defaultVal) {
  const raw = env(name);
  if (!raw) return defaultVal;
  const n = parseInt(raw, 10);
  return Number.isFinite(n) && n >= 0 ? n : defaultVal;
}

const data = $input.first().json;
const all = Array.isArray(data.skus) ? data.skus : [];
const maxSkus = envInt('CDP_DISPATCH_SAMPLE_SIZE', 0);
let skus = all;
let sampled = false;
if (maxSkus > 0 && all.length > maxSkus) {
  const copy = [...all];
  for (let i = copy.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    const tmp = copy[i];
    copy[i] = copy[j];
    copy[j] = tmp;
  }
  skus = copy.slice(0, maxSkus);
  sampled = true;
}

const batchGroupId = 'bg-' + Date.now().toString(36) + '-' + Math.random().toString(36).slice(2, 8);
try {
  if (typeof $getWorkflowStaticData === 'function') {
    const sd = $getWorkflowStaticData('global');
    sd.cdp_last_batch_group_id = batchGroupId;
  }
} catch (e) {}

let commandRoute = 'analisar';
try {
  const tg = $('🔀 Switch Comando (Telegram)').first().json;
  if (tg && tg.route) commandRoute = String(tg.route);
} catch (e) {}
if (commandRoute === 'analisar') {
  try {
    const em = $('🔀 Switch Comando (Email)').first().json;
    if (em && em.route) commandRoute = String(em.route);
  } catch (e) {}
}

return [
  {
    json: {
      ...data,
      skus,
      valid_skus: skus.length,
      dispatch_sampled: sampled,
      dispatch_sample_limit: maxSkus,
      dispatch_total_before_sample: all.length,
      batch_group_id: batchGroupId,
      command_route: commandRoute,
    },
  },
];

// cdp_router — Scraper POST /api/v1/jobs (force_refresh=false → Redis/PostgreSQL 24h cache).

const DEFAULT_BATCH_SIZE = 100;
const MAX_BATCH_SIZE = 100;
const DEFAULT_SITES = ['gm', 'ml', 'vw', 'eu', 'pecadireta'];
const DEFAULT_SCRAPER_API_BASE =
  'https://cdp-scrapers-api-prod.bravecoast-b14d791e.eastus2.azurecontainerapps.io';
const data = $input.first().json;
const skus = Array.isArray(data.skus) ? data.skus : [];

function env(name) {
  try {
    if (typeof $env !== 'undefined' && $env && $env[name]) {
      return String($env[name]).trim();
    }
  } catch (e) {}
  try {
    if (typeof process !== 'undefined' && process.env && process.env[name]) {
      return String(process.env[name]).trim();
    }
  } catch (e) {}
  return '';
}
function envList(name) {
  const raw = env(name);
  return raw ? raw.split(',').map((s) => s.trim()).filter(Boolean) : [];
}
function trimTrailingSlashes(value) {
  let out = String(value || '').trim();
  while (out.endsWith('/')) out = out.slice(0, -1);
  return out;
}
function trimSlashes(value) {
  let out = String(value || '').trim();
  while (out.startsWith('/')) out = out.slice(1);
  while (out.endsWith('/')) out = out.slice(0, -1);
  return out;
}
function readStaticRequester() {
  try {
    if (typeof $getWorkflowStaticData === 'function') {
      const sd = $getWorkflowStaticData('global');
      if (sd && sd.cdp_sheet_requester) return sd.cdp_sheet_requester;
    }
  } catch (e) {}
  return null;
}

const configuredSites = envList('CDP_SCRAPER_SITES');
const sites = configuredSites.length ? configuredSites : DEFAULT_SITES;
const commandRoute = String(data.command_route || 'analisar');
const scraperApiBase = trimTrailingSlashes(
  env('CDP_SCRAPER_API_BASE') || env('MUVSTOK_SCRAPER_API_BASE') || DEFAULT_SCRAPER_API_BASE
);
const apiKey = env('CDP_API_KEY') || env('MUVSTOK_API_KEY') || env('API_KEY');
const batchSizeRaw = Number(env('CDP_SCRAPER_BATCH_SIZE') || DEFAULT_BATCH_SIZE);
const BATCH_SIZE = Math.max(
  1,
  Math.min(MAX_BATCH_SIZE, Number.isFinite(batchSizeRaw) ? batchSizeRaw : DEFAULT_BATCH_SIZE)
);

const ctx = readStaticRequester();
let chatId = String(data.telegram_chat_id || data.chat_id || '').trim();
let emailFrom = String(data.email_from || '').trim();
if (ctx) {
  if (!chatId && ctx.chat_id) chatId = String(ctx.chat_id).trim();
  if (!emailFrom && ctx.email_from) emailFrom = String(ctx.email_from).trim();
}
const adHoc = !!(chatId || emailFrom);
let notify = 'none';
if (chatId) notify = 'telegram';
else if (emailFrom) notify = 'email';

const batchGroupId =
  String(data.batch_group_id || '').trim() ||
  'bg-' + Date.now().toString(36) + '-' + Math.random().toString(36).slice(2, 8);

let callbackUrl = env('CDP_N8N_WEBHOOK_URL');
if (!callbackUrl) {
  const base = trimTrailingSlashes(env('WEBHOOK_URL'));
  const rel = trimSlashes(env('CDP_N8N_WEBHOOK_PATH') || 'webhook/scraper-result');
  if (base) callbackUrl = base + '/' + rel;
}
if (!callbackUrl) callbackUrl = 'https://automacao.tktechnologies.com.br/webhook/scraper-result';

function encodeQueryParam(key, value) {
  return encodeURIComponent(key) + '=' + encodeURIComponent(String(value));
}
function buildQueryString(parts) {
  return parts.map(([k, v]) => encodeQueryParam(k, v)).join('&');
}
const queryParts = [
  ['notify', notify],
  ['batch_group_id', batchGroupId],
  ['dual_run', 'scraper'],
  ['command_route', commandRoute],
];
if (chatId) queryParts.push(['chat_id', chatId]);
if (emailFrom) queryParts.push(['reply_email', emailFrom]);
if (adHoc) queryParts.push(['ad_hoc', 'true']);
callbackUrl += (callbackUrl.includes('?') ? '&' : '?') + buildQueryString(queryParts);

const batches = [];
for (let i = 0; i < skus.length; i += BATCH_SIZE) {
  batches.push(skus.slice(i, i + BATCH_SIZE));
}
const totalBatches = batches.length;

return batches.map((batch, index) => ({
  json: {
    callback_url: callbackUrl,
    items: batch.map((it) => ({
      sku: it.sku,
      brand: it.brand || '',
      description: it.description || '',
    })),
    sheet_rows: batch.map((it) => ({
      sku: it.sku,
      row_number: it.row_number ?? null,
    })),
    sites,
    priority: 5,
    force_refresh: false,
    api_jobs_url: scraperApiBase + '/api/v1/jobs',
    api_key: apiKey,
    batch_group_id: batchGroupId,
    batch_index: index + 1,
    total_batches: totalBatches,
    batch_size: batch.length,
    ad_hoc: adHoc,
    notify,
    chat_id: chatId || undefined,
    reply_email: emailFrom,
    command_route: commandRoute,
    metadata: {
      source: 'cdp_router',
      pipeline: 'scraper',
      command_route: commandRoute,
      batch_group_id: batchGroupId,
      batch_index: index + 1,
      total_batches: totalBatches,
      cache_policy: 'redis_24h',
    },
  },
}));

// cdp_router — validate sheet rows, keep duplicate SKUs as real work items.
// Duplicate rows are intentionally preserved so every sheet row can receive data.

const raw = $input.all();
const seen = new Set();
const valid = [];
const dqIssues = [];
let skippedProcessado = 0;

function normalizeStatus(value) {
  return String(value || '')
    .trim()
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, ' ')
    .trim();
}

for (const item of raw) {
  const row = item.json;
  const rawSku = row.CODIGO ?? row.SKU ?? row.sku ?? row.codigo;
  const sku = rawSku ? String(rawSku).trim().toUpperCase() : '';

  const processado = normalizeStatus(row.PROCESSADO);
  if (processado === 'processado' || processado === 'sim' || processado === 'true') {
    skippedProcessado++;
    continue;
  }

  if (!sku) {
    dqIssues.push({ issue: 'EMPTY_SKU', row: JSON.stringify(row) });
    continue;
  }
  if (sku.length < 3) {
    dqIssues.push({ issue: 'SHORT_SKU', sku });
    continue;
  }
  if (seen.has(sku)) {
    dqIssues.push({
      issue: 'DUPLICATE_SKU',
      sku,
      row_number: row.row_number ?? null,
      action: 'included',
    });
  }
  seen.add(sku);

  valid.push({
    sku,
    brand: row.UNIDADE ? String(row.UNIDADE).trim() : '',
    description: row.ITEM ? String(row.ITEM).trim() : '',
    row_number: row.row_number ?? null,
    notify_email: row['E-MAIL'] ? String(row['E-MAIL']).trim() : '',
    notify_phone: row.CONTATO ? String(row.CONTATO).trim() : '',
  });
}

const duplicateIssues = dqIssues.filter((i) => i.issue === 'DUPLICATE_SKU');
const duplicateSkus = [...new Set(duplicateIssues.map((i) => i.sku).filter(Boolean))];

return [
  {
    json: {
      total_read: raw.length,
      valid_skus: valid.length,
      unique_skus: seen.size,
      skipped_processado: skippedProcessado,
      duplicates: duplicateIssues.length,
      duplicate_skus: duplicateSkus,
      empty_skus: dqIssues.filter((i) => i.issue === 'EMPTY_SKU').length,
      short_skus: dqIssues.filter((i) => i.issue === 'SHORT_SKU').length,
      dq_issues: dqIssues,
      skus: valid,
      dispatched_at: new Date().toISOString(),
    },
  },
];

// ─── Telegram Command Router v4 — adds .status / .andamento ─────────────────

const DEFAULT_SCRAPER_API_BASE =
  'https://cdp-scrapers-api-prod.bravecoast-b14d791e.eastus2.azurecontainerapps.io';

function envValue(name) {
  try {
    if (typeof $env !== 'undefined' && $env && $env[name]) {
      return String($env[name]).trim();
    }
  } catch (e) {
    return '';
  }
  try {
    if (typeof process !== 'undefined' && process.env && process.env[name]) {
      return String(process.env[name]).trim();
    }
  } catch (e) {
    return '';
  }
  return '';
}

function envList(name) {
  const raw = envValue(name);
  return raw ? raw.split(',').map((s) => s.trim()).filter(Boolean) : [];
}

function statusCommands() {
  const raw = envList('CDP_STATUS_COMMANDS');
  if (raw.length) return raw;
  return ['.status', '.andamento', '.progresso'];
}

function trimTrailingSlashes(value) {
  let out = String(value || '').trim();
  while (out.endsWith('/')) out = out.slice(0, -1);
  return out;
}

function scraperApiBase() {
  return trimTrailingSlashes(
    envValue('CDP_SCRAPER_API_BASE') ||
      envValue('MUVSTOK_SCRAPER_API_BASE') ||
      DEFAULT_SCRAPER_API_BASE
  );
}

function cdpApiKey() {
  return envValue('CDP_API_KEY') || envValue('MUVSTOK_API_KEY') || envValue('API_KEY');
}

function telegramBotToken() {
  return (
    envValue('TELEGRAM_BOT_TOKEN') ||
    envValue('TELEGRAM_TOKEN') ||
    envValue('TELEGRAM_API_TOKEN')
  );
}

const msg = $input.first().json;
const chatId = String(msg.message?.chat?.id || '');
const username = String(msg.message?.from?.username || msg.message?.from?.first_name || '');
const text = String(msg.message?.text || msg.message?.caption || '').trim();
const doc = msg.message?.document || null;
const hasFile = !!doc;

const allowed = envList('TELEGRAM_ALLOWED_CHAT_IDS');
if (allowed.length && !allowed.includes(chatId)) {
  return [{ json: { route: 'unauthorized', chat_id: chatId } }];
}

const lower = text.toLowerCase();
const isAnalisar = lower.startsWith('.analisar');
const isSku = lower.startsWith('.sku');
const isStatus = statusCommands().some((cmd) => lower.startsWith(cmd.toLowerCase()));

if (isStatus) {
  const base = scraperApiBase();
  return [
    {
      json: {
        route: 'status',
        chat_id: chatId,
        username,
        origem: 'telegram',
        notify: chatId,
        dispatch_runs_lookup_url:
          base + '/api/v1/dispatch-runs/active/for-chat/' + encodeURIComponent(chatId),
        dispatch_runs_api_key: cdpApiKey(),
      },
    },
  ];
}

if (isSku || hasFile) {
  const afterCmd = isSku ? text.slice(4).trim() : '';
  const textSkus = afterCmd
    .split(/[\n,;\s]+/)
    .map((s) => s.trim().toUpperCase())
    .filter((s) => /^[A-Z0-9]{5,}$/.test(s))
    .slice(0, 200);

  if (hasFile && textSkus.length > 0) {
    return [
      {
        json: {
          route: 'sku_both',
          chat_id: chatId,
          username,
          text_skus: textSkus,
          file_id: doc.file_id,
          file_name: doc.file_name || 'attachment',
          telegram_bot_token: telegramBotToken(),
          origem: 'telegram',
          notify: chatId,
        },
      },
    ];
  }
  if (hasFile && textSkus.length === 0) {
    return [
      {
        json: {
          route: 'sku_file',
          chat_id: chatId,
          username,
          text_skus: [],
          file_id: doc.file_id,
          file_name: doc.file_name || 'attachment',
          telegram_bot_token: telegramBotToken(),
          origem: 'telegram',
          notify: chatId,
        },
      },
    ];
  }
  if (!hasFile && textSkus.length > 0) {
    return [
      {
        json: {
          route: 'sku_text',
          chat_id: chatId,
          username,
          text_skus: textSkus,
          origem: 'telegram',
          notify: chatId,
        },
      },
    ];
  }
  return [
    {
      json: {
        route: 'sku_empty',
        chat_id: chatId,
        username,
        origem: 'telegram',
        notify: chatId,
      },
    },
  ];
}

if (isAnalisar) {
  return [
    {
      json: {
        route: 'analisar',
        chat_id: chatId,
        username,
        is_full_sheet_trigger: true,
        origem: 'telegram',
        notify: chatId,
      },
    },
  ];
}

return [{ json: { route: 'ignore', chat_id: chatId } }];

// ─── Email Command Router v4 ─────────────────────────────────────────────
// v4: Detects attachments in both simple mode (msg.attachments) and raw mode
//     (msg.payload.parts[]) from Gmail Trigger with simple=false.
//     Passes messageId for downstream attachment download.
function envList(name) {
  try {
    const raw = (typeof process !== 'undefined' && process.env && process.env[name]) || '';
    return raw.split(',').map(s => s.trim()).filter(Boolean);
  } catch(e) { return []; }
}

const msg = $input.first().json;
let fromEmail = '';
if (msg.from?.value?.[0]?.address) fromEmail = String(msg.from.value[0].address).trim().toLowerCase();
else if (typeof msg.from === 'string') fromEmail = msg.from.trim().toLowerCase();

// ── Auth check ──
const allowed = envList('EMAIL_ALLOWED_SENDERS').map(s => s.toLowerCase());
if (allowed.length && !allowed.some(a => fromEmail.includes(a))) {
  return [{ json: { route: 'unauthorized', email_from: fromEmail } }];
}

// ── Read subject + body ──
const subject = String(msg.subject || '').trim();
const bodyRaw = String(msg.textPlain || msg.text || msg.html || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();

const subjectL = subject.toLowerCase();
const bodyLines = bodyRaw.split(/\r?\n/).map(l => l.trim()).filter(Boolean);
const bodyFirstL = (bodyLines[0] || '').toLowerCase();
let cmdSource;
if (subjectL.startsWith('.analisar') || subjectL.startsWith('.sku')) {
  cmdSource = subject;
} else if (bodyFirstL.startsWith('.analisar') || bodyFirstL.startsWith('.sku')) {
  cmdSource = bodyRaw;
} else {
  cmdSource = subject || bodyRaw;
}
const lower = cmdSource.toLowerCase();

// ── Attachment check: simple mode (msg.attachments) ──
const attachments = msg.attachments || [];
let xlsAttachment = attachments.find(a =>
  /\.(xlsx?|csv)$/i.test(a.name || a.filename || '')
);
let messageId = String(msg.id || msg.messageId || '').trim();

// ── Attachment check: raw mode (msg.payload.parts[]) ──
// Gmail Trigger with simple=false returns raw Gmail API structure
if (!xlsAttachment && msg.payload && msg.payload.parts) {
  const parts = msg.payload.parts;
  // Flatten: some emails nest parts inside parts (multipart/mixed > multipart/alternative + attachment)
  const allParts = [];
  function collectParts(partsList) {
    for (const p of partsList) {
      allParts.push(p);
      if (p.parts) collectParts(p.parts);
    }
  }
  collectParts(parts);

  for (const part of allParts) {
    const fn = String(part.filename || '').trim();
    if (/\.(xlsx?|csv)$/i.test(fn) && part.body && part.body.attachmentId) {
      xlsAttachment = {
        id: part.body.attachmentId,
        name: fn,
        mimeType: part.mimeType || '',
        size: part.body.size || 0
      };
      break;
    }
  }
  // Also try to get messageId from raw payload
  if (!messageId && msg.payload.headers) {
    const msgIdHeader = msg.payload.headers.find(h => h.name?.toLowerCase() === 'message-id');
    if (msgIdHeader) messageId = String(msgIdHeader.value || '').trim();
  }
}

// Fallback messageId from threadId or any id on the message root
if (!messageId) messageId = String(msg.threadId || '').trim();

const hasFile = !!xlsAttachment;

const isAnalisar = lower.startsWith('.analisar');
const isSku      = lower.startsWith('.sku');

if (isSku || hasFile) {
  const afterCmd = isSku ? cmdSource.slice(4).trim() : '';
  const textSkus = afterCmd
    .split(/[\n,;\s]+/)
    .map(s => s.trim().toUpperCase())
    .filter(s => /^[A-Z0-9]{5,}$/.test(s))
    .slice(0, 200);

  const baseOut = {
    email_from: fromEmail,
    notify: fromEmail,
    origem: 'email',
    message_id: messageId
  };

  if (hasFile && textSkus.length > 0) {
    return [{ json: { route: 'sku_both', ...baseOut, text_skus: textSkus,
      attachment_id: xlsAttachment.id || '', attachment_name: xlsAttachment.name || xlsAttachment.filename || '' }}];
  }
  if (hasFile && textSkus.length === 0) {
    return [{ json: { route: 'sku_file', ...baseOut,
      attachment_id: xlsAttachment.id || '', attachment_name: xlsAttachment.name || xlsAttachment.filename || '' }}];
  }
  if (!hasFile && textSkus.length > 0) {
    return [{ json: { route: 'sku_text', ...baseOut, text_skus: textSkus }}];
  }
  return [{ json: { route: 'sku_empty', ...baseOut }}];
}

if (isAnalisar) {
  return [{ json: { route: 'analisar', email_from: fromEmail, notify: fromEmail,
    is_full_sheet_trigger: true, origem: 'email', message_id: messageId }}];
}

return [{ json: { route: 'ignore', email_from: fromEmail } }];

const d = $input.first().json;
const skus = (d.text_skus || []).map(s => ({ sku: s, brand: '', description: '' }));
return [{ json: {
  total_read: skus.length, valid_skus: skus.length,
  skipped_processado: 0, duplicates: 0, empty_skus: 0, short_skus: 0,
  skus, dispatched_at: new Date().toISOString(),
  origem: d.origem || 'telegram',
  telegram_chat_id: d.chat_id || '',
  notify: d.notify || d.chat_id || ''
}}];

// Receives rows from SpreadsheetFile — find SKU-like column
const rows = $input.all();
const routerData = $('🔀 Switch Comando (Telegram)').first().json;
const chatId = String(routerData.chat_id || routerData.notify || '');
